struct Solution;

use std::collections::{BinaryHeap, HashMap};

impl Solution {
    fn append_zeros(num: &Vec<u8>, repeat: usize) -> Vec<u8> {

        /*
        let mut prefixed_num = match repeat {
            1 => vec![48],
            2 => vec![48,48],
            3 => vec![48,48,48],
            4 => vec![48,48,48,48],
            5 => vec![48,48,48,48,48],
            6 => vec![48,48,48,48,48,48],
            _ => vec![],
        };

        prefixed_num.extend(num);
        prefixed_num
        */

        let mut zero_prefixed_num = std::iter::repeat("0")
                .take(repeat)
                .collect::<String>()
                .as_bytes()
                .to_vec();

        zero_prefixed_num.extend(num);
        zero_prefixed_num
    }

    fn check_swapped_pair(num_1: i32, num_2: i32) -> bool {
        let mut diff_index = Vec::with_capacity(6);
        let (num_1, mut num_2) = (
            num_1.to_string().as_bytes().to_vec(),
            num_2.to_string().as_bytes().to_vec(),
        );
        if num_2.len() < num_1.len() {
            num_2 = Solution::append_zeros(&num_2, num_1.len() - num_2.len())
        }
        for (i, _) in num_1.iter().enumerate() {
            if num_1[i] != num_2[i] && diff_index.len() < 5 {
                diff_index.push(i);
            }
        }
        match diff_index.len() {
            4 => {
                (num_1[diff_index[0]] == num_2[diff_index[1]]
                    && num_1[diff_index[1]] == num_2[diff_index[0]]
                    && num_1[diff_index[2]] == num_2[diff_index[3]]
                    && num_1[diff_index[3]] == num_2[diff_index[2]])
                    || (num_1[diff_index[0]] == num_2[diff_index[2]]
                        && num_1[diff_index[2]] == num_2[diff_index[0]]
                        && num_1[diff_index[1]] == num_2[diff_index[3]]
                        && num_1[diff_index[3]] == num_2[diff_index[1]])
                    || (num_1[diff_index[0]] == num_2[diff_index[3]]
                        && num_1[diff_index[3]] == num_2[diff_index[0]]
                        && num_1[diff_index[1]] == num_2[diff_index[2]]
                        && num_1[diff_index[2]] == num_2[diff_index[1]])
            }
            3 => {
                (num_1[diff_index[0]] == num_2[diff_index[1]]
                    && num_1[diff_index[1]] == num_2[diff_index[2]]
                    && num_1[diff_index[2]] == num_2[diff_index[0]])
                    || (num_1[diff_index[0]] == num_2[diff_index[2]]
                        && num_1[diff_index[2]] == num_2[diff_index[1]]
                        && num_1[diff_index[1]] == num_2[diff_index[0]])
            }
            2 => {
                num_1[diff_index[0]] == num_2[diff_index[1]]
                    && num_1[diff_index[1]] == num_2[diff_index[0]]
            }
            _ => return false,
        }
    }

    pub fn count_pairs(nums: Vec<i32>) -> i32 {
        let mut num_freq = HashMap::with_capacity(nums.len());
        //let mut sorted_nums = BinaryHeap::with_capacity(nums.len());
        for num in nums.into_iter() {
            match num_freq.get_mut(&num) {
                None => {
                    num_freq.insert(num, 1);
                }
                Some(f) => *f += 1,
            }
        }
        /*
        for (k,v) in num_freq.into_iter() {
            sorted_nums.push((k,v));
        }

        let mut sum = 0;
        while sorted_nums.len() != 0 {
            let (num_1 , freq_1)= sorted_nums.pop().unwrap();
               sum += freq_1 * (freq_1 - 1)/2 + freq_1 * sorted_nums.iter().map( 
                   |(num_2, freq_2)| {
                       if num_1 == *num_2 || Solution::check_swapped_pair(num_1, *num_2) {
                           return *freq_2;
                       }
                       0
                   }).sum::<i32>();
        }
        sum
        */
        let mut nums = num_freq.iter().map(|(&k,&v)| (k,v)).collect::<Vec<(i32,i32)>>();
        nums.sort_by(|(a1,_),(b1,_)| b1.cmp(&a1));
        let (mut matches, mut sum) = (0,0);
        for (i, (num_1, freq_1)) in nums.iter().enumerate() {
            matches = 0;
            for (num_2 , freq_2)in nums[i+1..].iter() {
                if num_1 == num_2 || Solution::check_swapped_pair(*num_1, *num_2) {
                    matches += freq_2;
                }
            }
            sum += freq_1 * (freq_1 - 1) / 2  + freq_1 * matches
        }
        sum
        /*
        nums.iter()
            .enumerate()
            .map(|(i, (num_1, freq_1))| {
                freq_1 * (freq_1- 1) / 2 + freq_1 * nums[i + 1..]
                    .iter()
                    .map(|(num_2, freq_2)| {
                        if num_1 == num_2 || Solution::check_swapped_pair(*num_1, *num_2) {
                            return *freq_2;
                        }
                        0
                    })
                    .sum::<i32>()
            })
            .sum::<i32>()
        */
    }
}

